import modal

app = modal.App("text-pipeline")
image = modal.Image.debian_slim()

@app.function(image=image)
def clean_text(text: str) -> str:
    """Strips leading and trailing whitespace and converts to lowercase."""
    return text.strip().lower()

@app.function(image=image)
def count_words(text: str) -> int:
    """Counts the number of words in the given text."""
    return len(text.split())

@app.function(image=image)
def summarize(original_text: str, word_count: int) -> dict:
    """Returns a summary dictionary with lengths and word count."""
    cleaned_text = original_text.strip().lower()
    return {
        "original_length": len(original_text),
        "word_count": word_count,
        "cleaned_length": len(cleaned_text),
    }

@app.local_entrypoint()
def main():
    sample_text = "  Hello World this is a TEST of the pipeline  "

    # 1. Clean the text
    cleaned_text = clean_text.remote(sample_text)

    # 2. Count words in the cleaned text
    word_count = count_words.remote(cleaned_text)

    # 3. Get summary
    summary = summarize.remote(sample_text, word_count)

    # 4. Store results in a Modal Dict
    output_dict = modal.Dict.from_name("text-pipeline-output", create_if_missing=True)
    output_dict["summary"] = summary
    output_dict["pipeline_stages"] = 3

    print(f"Pipeline completed. Summary: {summary}")
